import{_ as t,o as r,c as o,ag as n}from"./chunks/framework.CvgP6Fyv.js";const c=JSON.parse('{"title":"Gegevens importeren & exporteren","description":"","frontmatter":{},"headers":[],"relativePath":"nl/account/data.md","filePath":"nl/account/data.md"}'),a={name:"nl/account/data.md"};function l(i,e,s,d,p,g){return r(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="gegevens-importeren-exporteren" tabindex="-1">Gegevens importeren &amp; exporteren <a class="header-anchor" href="#gegevens-importeren-exporteren" aria-label="Permalink to &quot;Gegevens importeren &amp; exporteren&quot;">​</a></h1><p>Importeer bestaande gegevens in MyCompanyDesk en exporteer je administratie voor back-up of gebruik in andere tools.</p><h2 id="importeren" tabindex="-1">Importeren <a class="header-anchor" href="#importeren" aria-label="Permalink to &quot;Importeren&quot;">​</a></h2><h3 id="csv-import" tabindex="-1">CSV-import <a class="header-anchor" href="#csv-import" aria-label="Permalink to &quot;CSV-import&quot;">​</a></h3><p>Importeer gegevens vanuit CSV-bestanden voor:</p><ul><li><strong>Klanten</strong> — Naam, e-mail, telefoon, adres, BTW-nummer</li><li><strong>Facturen</strong> — Factuurgegevens met regelitems</li><li><strong>Uitgaven</strong> — Uitgavenrecords met categorieen</li><li><strong>Projecten</strong> — Projectnamen en details</li><li><strong>Objecten</strong> — Activarecords</li></ul><h3 id="hoe-te-importeren" tabindex="-1">Hoe te importeren <a class="header-anchor" href="#hoe-te-importeren" aria-label="Permalink to &quot;Hoe te importeren&quot;">​</a></h3><ol><li>Ga naar <strong>Profiel &gt; Importeren</strong></li><li>Selecteer het <strong>gegevenstype</strong> dat je wilt importeren</li><li>Upload je <strong>CSV-bestand</strong></li><li><strong>Kolommen koppelen</strong> — Koppel je CSV-kolomkoppen aan MyCompanyDesk-velden</li><li><strong>Voorbeeld</strong> — Controleer de gegevens voor het importeren</li><li><strong>Bevestigen</strong> — Klik op Importeren om de records aan te maken</li></ol><h3 id="importtips" tabindex="-1">Importtips <a class="header-anchor" href="#importtips" aria-label="Permalink to &quot;Importtips&quot;">​</a></h3><ul><li>Gebruik UTF-8-codering voor je CSV-bestanden</li><li>Voeg een koprij toe met kolomnamen</li><li>Datumnotaties moeten consistent zijn (JJJJ-MM-DD aanbevolen)</li><li>Bedragvelden moeten een punt (.) als decimaalteken gebruiken</li><li>Lege velden worden overgeslagen (bestaande standaardwaarden worden gebruikt)</li></ul><h3 id="kolomkoppeling" tabindex="-1">Kolomkoppeling <a class="header-anchor" href="#kolomkoppeling" aria-label="Permalink to &quot;Kolomkoppeling&quot;">​</a></h3><p>De importwizard toont je CSV-kolommen en laat je elke kolom koppelen aan het bijbehorende MyCompanyDesk-veld. Veelgebruikte koppelingen:</p><table tabindex="0"><thead><tr><th>CSV-kolom</th><th>Koppelt aan</th></tr></thead><tbody><tr><td>Bedrijfsnaam / Naam</td><td>Klantnaam</td></tr><tr><td>E-mail</td><td>Klant-e-mail</td></tr><tr><td>Straat / Adres</td><td>Straatadres</td></tr><tr><td>Postcode</td><td>Postcode</td></tr><tr><td>Plaats</td><td>Plaats</td></tr><tr><td>BTW</td><td>BTW-nummer</td></tr><tr><td>Telefoon</td><td>Telefoonnummer</td></tr></tbody></table><h2 id="exporteren" tabindex="-1">Exporteren <a class="header-anchor" href="#exporteren" aria-label="Permalink to &quot;Exporteren&quot;">​</a></h2><h3 id="csv-export" tabindex="-1">CSV-export <a class="header-anchor" href="#csv-export" aria-label="Permalink to &quot;CSV-export&quot;">​</a></h3><p>Exporteer je gegevens als CSV vanaf de betreffende lijstpagina&#39;s:</p><ul><li><strong>Facturen</strong> — Alle facturen met bedragen, datums, statussen</li><li><strong>Uitgaven</strong> — Alle uitgaven met categorieen en bedragen</li><li><strong>Klanten</strong> — Je klantendatabase</li></ul><p>Klik op de <strong>Exporteren</strong>-knop op de lijstpagina om te downloaden.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>CSV-export vereist het <strong>Pro</strong>-abonnement of hoger.</p></div><h3 id="avg-gegevensexport" tabindex="-1">AVG-gegevensexport <a class="header-anchor" href="#avg-gegevensexport" aria-label="Permalink to &quot;AVG-gegevensexport&quot;">​</a></h3><p>Exporteer al je persoonlijke gegevens in JSON-formaat:</p><ol><li>Ga naar <strong>Profiel &gt; Gegevens</strong></li><li>Klik op <strong>Mijn gegevens exporteren</strong></li><li>Download het JSON-bestand met al je accountgegevens</li></ol><p>Deze AVG-export bevat:</p><ul><li>Je profielinformatie</li><li>Alle facturen, uitgaven, offertes</li><li>Klantrecords</li><li>Project- en tijdgegevens</li><li>Instellingen en voorkeuren</li></ul><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li>Exporteer je gegevens regelmatig als back-up</li><li>Gebruik CSV-export om gegevens te delen met je boekhouder</li><li>Wanneer je overstapt van een andere tool, gebruik dan de importwizard om je klantenlijst te migreren</li><li>De AVG-export biedt een compleet overzicht van je gegevens</li></ul>',26)])])}const h=t(a,[["render",l]]);export{c as __pageData,h as default};
